module top_module(
    q,
    rst_clk,
    d,
    reset_b
);output q;
    input rst_clk;
    input d;
    input reset_b;

    reg q;

    always @(posedge rst_clk or negedge reset_b) begin
        if (~reset_b) begin
            q <= 1'b0;
        end else begin
            q <= d;
        end
    end

endmodule
